import{_ as e,o as r,c as i,ah as h}from"./chunks/framework.BNo2o5Ln.js";const b=JSON.parse('{"title":"Python","description":"","frontmatter":{"title":"Python","order":13},"headers":[],"relativePath":"server/python/index.md","filePath":"server/python/index.md"}'),n={name:"server/python/index.md"};function t(l,a,d,o,s,c){return r(),i("div",null,[...a[0]||(a[0]=[h('<h1 id="python" tabindex="-1">Python <a class="header-anchor" href="#python" aria-label="Permalink to “Python”">​</a></h1><p>Python 是解释型、动态类型语言，以简洁、易读、生态丰富著称。Python 在 Web 开发、数据处理、机器学习中有广泛应用。</p><h2 id="gil-全局解释器锁" tabindex="-1">GIL（全局解释器锁） <a class="header-anchor" href="#gil-全局解释器锁" aria-label="Permalink to “GIL（全局解释器锁）”">​</a></h2><h3 id="gil-的原理" tabindex="-1">GIL 的原理 <a class="header-anchor" href="#gil-的原理" aria-label="Permalink to “GIL 的原理”">​</a></h3><p>GIL 是 Python 解释器的全局锁，保证同一时刻只有一个线程执行 Python 字节码。</p><h3 id="gil-的影响" tabindex="-1">GIL 的影响 <a class="header-anchor" href="#gil-的影响" aria-label="Permalink to “GIL 的影响”">​</a></h3><p>多线程无法并行执行 CPU 密集型任务。多进程可以绕过 GIL。</p><h3 id="绕过-gil" tabindex="-1">绕过 GIL <a class="header-anchor" href="#绕过-gil" aria-label="Permalink to “绕过 GIL”">​</a></h3><p>多进程、C 扩展、异步编程。</p><h2 id="异步编程" tabindex="-1">异步编程 <a class="header-anchor" href="#异步编程" aria-label="Permalink to “异步编程”">​</a></h2><h3 id="asyncio" tabindex="-1">asyncio <a class="header-anchor" href="#asyncio" aria-label="Permalink to “asyncio”">​</a></h3><p>asyncio 是 Python 的异步编程库，基于事件循环和协程。async def 定义协程，await 等待 Future 完成。</p><h3 id="协程的优势" tabindex="-1">协程的优势 <a class="header-anchor" href="#协程的优势" aria-label="Permalink to “协程的优势”">​</a></h3><p>协程是用户态的轻量级线程，切换开销小。协程适合 I/O 密集型任务。</p><h2 id="web-框架" tabindex="-1">Web 框架 <a class="header-anchor" href="#web-框架" aria-label="Permalink to “Web 框架”">​</a></h2><h3 id="django" tabindex="-1">Django <a class="header-anchor" href="#django" aria-label="Permalink to “Django”">​</a></h3><p>全栈 Web 框架，包含 ORM、模板引擎、认证系统。</p><h3 id="flask" tabindex="-1">Flask <a class="header-anchor" href="#flask" aria-label="Permalink to “Flask”">​</a></h3><p>微框架，只包含核心功能。</p><h3 id="fastapi" tabindex="-1">FastAPI <a class="header-anchor" href="#fastapi" aria-label="Permalink to “FastAPI”">​</a></h3><p>现代 Web 框架，基于 asyncio 和 Pydantic，高性能。</p><h2 id="类型提示" tabindex="-1">类型提示 <a class="header-anchor" href="#类型提示" aria-label="Permalink to “类型提示”">​</a></h2><h3 id="类型提示的语法" tabindex="-1">类型提示的语法 <a class="header-anchor" href="#类型提示的语法" aria-label="Permalink to “类型提示的语法”">​</a></h3><p>Python 3.5+ 引入类型提示，使用 typing 模块。</p><h3 id="pydantic" tabindex="-1">Pydantic <a class="header-anchor" href="#pydantic" aria-label="Permalink to “Pydantic”">​</a></h3><p>Pydantic 是数据验证库，基于类型提示。FastAPI 使用 Pydantic 验证请求体。</p><h2 id="适合场景" tabindex="-1">适合场景 <a class="header-anchor" href="#适合场景" aria-label="Permalink to “适合场景”">​</a></h2><h3 id="适合" tabindex="-1">适合 <a class="header-anchor" href="#适合" aria-label="Permalink to “适合”">​</a></h3><p>Web 开发、数据处理、机器学习、脚本和自动化。</p><h3 id="不适合" tabindex="-1">不适合 <a class="header-anchor" href="#不适合" aria-label="Permalink to “不适合”">​</a></h3><p>高性能服务、CPU 密集型任务、内存受限应用。</p>',31)])])}const P=e(n,[["render",t]]);export{b as __pageData,P as default};
